import { render, type RenderOptions } from '@testing-library/react'
import { AppProviders } from '../providers/AppProviders'

/** Wraps component in the production provider stack for tests that use Mantine components. */
export function renderWithMantine(ui: React.ReactElement, options?: RenderOptions) {
  return render(ui, {
    wrapper: ({ children }) => <AppProviders>{children}</AppProviders>,
    ...options,
  })
}

import { useEffect } from 'react'
import { Routes, Route } from 'react-router-dom'
import { Header } from '@/components/layout/Header'
import { Footer } from '@/components/layout/Footer'
import { useWebMCP } from '@/hooks/useWebMCP'
import { useAuthStore } from '@/stores/authStore'
import { usePreferencesStore } from '@/stores/preferencesStore'
import { About } from '@/pages/About'
import { AuthCallback } from '@/pages/AuthCallback'
import { Home } from '@/pages/Home'
import { Search } from '@/pages/Search'

export function App() {
  useWebMCP()

  const initialize = useAuthStore((s) => s.initialize)
  const session = useAuthStore((s) => s.session)
  const loadPreferences = usePreferencesStore((s) => s.load)
  const clearPreferences = usePreferencesStore((s) => s.clear)

  useEffect(() => {
    initialize()
  }, [initialize])

  useEffect(() => {
    if (session) {
      loadPreferences()
    } else {
      clearPreferences()
    }
  }, [session, loadPreferences, clearPreferences])

  return (
    <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column' }}>
      <Header />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/auth/callback" element={<AuthCallback />} />
        <Route path="/search" element={<Search />} />
      </Routes>
      <Footer />
    </div>
  )
}

import { MantineProvider } from '@mantine/core'
import { theme } from '../theme'

/** Shared provider stack used by both production (main.tsx) and tests. */
export function AppProviders({ children }: { children: React.ReactNode }) {
  return <MantineProvider theme={theme}>{children}</MantineProvider>
}

import { describe, it, expect, vi, afterEach, beforeEach } from 'vitest'
import { render, screen, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MantineProvider } from '@mantine/core'
import type { SearchField } from './types'
import { FilterControl, MultiSelectCheckboxes } from './FilterControl'

const mockPreferencesStore = {
  homeLatitude: null as number | null,
  homeLongitude: null as number | null,
  homeState: null as string | null,
  loaded: false,
  loading: false,
  load: vi.fn(),
  update: vi.fn(),
  clear: vi.fn(),
}

vi.mock('@/stores/preferencesStore', () => ({
  usePreferencesStore: (selector: (s: typeof mockPreferencesStore) => unknown) =>
    selector(mockPreferencesStore),
}))

beforeEach(() => {
  mockPreferencesStore.homeLatitude = null
  mockPreferencesStore.homeLongitude = null
  mockPreferencesStore.homeState = null
})

afterEach(() => {
  vi.useRealTimers()
})

function renderWithTooltips(ui: React.ReactElement) {
  return render(<MantineProvider>{ui}</MantineProvider>)
}

// ── Fixtures ──────────────────────────────────────────────────────────────────

const textField: SearchField = {
  __typename: 'TextSearchField',
  name: 'name',
  label: 'Institution Name',
  description: 'Full-text search on institution name',
  theme: 'CORE',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: true,
}

const binaryField: SearchField = {
  __typename: 'BinarySearchField',
  name: 'hbcu',
  label: 'HBCU',
  description: 'Historically Black Colleges and Universities',
  theme: 'ACADEMICS',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: false,
}

const singleSelectField: SearchField = {
  __typename: 'ChoiceSearchField',
  name: 'control',
  label: 'Control',
  description: 'Institution control type',
  theme: 'ACADEMICS',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: false,
  options: [
    { value: '1', displayName: 'Public' },
    { value: '2', displayName: 'Private nonprofit' },
  ],
  maxSelections: 1,
}

const multiSelectField: SearchField = {
  __typename: 'ChoiceSearchField',
  name: 'platforms',
  label: 'Platforms',
  description: 'Application platforms',
  theme: 'ADMISSIONS',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: false,
  options: [
    { value: 'a', displayName: 'Alpha' },
    { value: 'b', displayName: 'Beta' },
    { value: 'c', displayName: 'Gamma' },
  ],
  maxSelections: null,
}

const displayOnlyField: SearchField = {
  __typename: 'TextSearchField',
  name: 'city',
  label: 'City',
  description: 'City',
  theme: 'LOCATION',
  visibility: 'VISIBLE',
  searchability: 'NOT_SEARCHABLE',
  exportable: true,
}

const numericalField: SearchField = {
  __typename: 'NumericalSearchField',
  name: 'tuition',
  label: 'Tuition',
  description: 'Annual tuition cost',
  theme: 'COST',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: true,
  unit: 'DOLLARS',
  min: 0,
  max: 80000,
  step: 1000,
}

const admissionRateField: SearchField = {
  __typename: 'NumericalRangeSearchField',
  name: 'admission_rate',
  label: 'Admission Rate',
  description: 'Percentage of applicants admitted',
  theme: 'OUTCOMES',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: true,
  unit: 'PERCENTAGE',
  min: 0,
  max: 1,
  step: 0.01,
}

const enrollmentField: SearchField = {
  __typename: 'NumericalRangeSearchField',
  name: 'enrollment',
  label: 'Enrollment',
  description: 'Total enrollment',
  theme: 'ACADEMICS',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: true,
  min: 0,
  max: 100000,
  step: 100,
}

const geoField: SearchField = {
  __typename: 'GeoSearchField',
  name: 'location',
  label: 'Location',
  description: 'Geographic proximity',
  theme: 'LOCATION',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: false,
  defaultLatitude: 42.36,
  defaultLongitude: -71.06,
  maxRadiusMiles: 100,
}

const geoFieldNoDefaults: SearchField = {
  __typename: 'GeoSearchField',
  name: 'location',
  label: 'Location',
  description: 'Geographic proximity',
  theme: 'LOCATION',
  visibility: 'VISIBLE',
  searchability: 'SEARCHABLE',
  exportable: false,
  maxRadiusMiles: 200,
}

// ── FilterControl ─────────────────────────────────────────────────────────────

describe('FilterControl', () => {
  it('renders a text input for TextSearchField', () => {
    renderWithTooltips(<FilterControl field={textField} value={undefined} onChange={vi.fn()} />)
    expect(screen.getByRole('textbox', { name: /institution name/i })).toBeInTheDocument()
  })

  it('renders text value from { query } prop', () => {
    renderWithTooltips(
      <FilterControl field={textField} value={{ query: 'MIT' }} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('textbox', { name: /institution name/i })).toHaveValue('MIT')
  })

  it('calls onChange with { query } when typing in text field (after debounce)', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(<FilterControl field={textField} value={undefined} onChange={onChange} />)
    await user.type(screen.getByRole('textbox', { name: /institution name/i }), 'A')
    await waitFor(() => expect(onChange).toHaveBeenCalledWith({ query: 'A' }), { timeout: 1000 })
  })

  it('calls onChange with undefined when clearing text field (after debounce)', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl field={textField} value={{ query: 'A' }} onChange={onChange} />,
    )
    await user.clear(screen.getByRole('textbox', { name: /institution name/i }))
    await waitFor(() => expect(onChange).toHaveBeenCalledWith(undefined), { timeout: 1000 })
  })

  it('renders a checkbox for BinarySearchField', () => {
    renderWithTooltips(<FilterControl field={binaryField} value={undefined} onChange={vi.fn()} />)
    expect(screen.getByRole('checkbox', { name: /hbcu/i })).toBeInTheDocument()
  })

  it('toggles binary checkbox on click', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(<FilterControl field={binaryField} value={undefined} onChange={onChange} />)
    await user.click(screen.getByRole('checkbox', { name: /hbcu/i }))
    expect(onChange).toHaveBeenCalledWith({ value: '1' })
  })

  it('renders a <select> for single-select ChoiceSearchField', () => {
    renderWithTooltips(
      <FilterControl field={singleSelectField} value={undefined} onChange={vi.fn()} />,
    )
    const select = screen.getByRole('combobox', { name: /control/i })
    expect(select.tagName).toBe('SELECT')
    expect(select.querySelectorAll('option')).toHaveLength(3) // Any + 2 options
  })

  it('calls onChange with { value } when selecting an option', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl field={singleSelectField} value={undefined} onChange={onChange} />,
    )
    await user.selectOptions(screen.getByRole('combobox', { name: /control/i }), '1')
    expect(onChange).toHaveBeenCalledWith({ value: '1' })
  })

  it('renders checkboxes for multi-select ChoiceSearchField', () => {
    renderWithTooltips(
      <FilterControl field={multiSelectField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('checkbox', { name: /alpha/i })).toBeInTheDocument()
    expect(screen.getByRole('checkbox', { name: /beta/i })).toBeInTheDocument()
  })

  it('renders display-only label for NOT_SEARCHABLE fields', () => {
    renderWithTooltips(
      <FilterControl field={displayOnlyField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByText('City')).toBeInTheDocument()
    expect(screen.getByText(/display only/i)).toBeInTheDocument()
  })

  // ── GeoSearchField ─────────────────────────────────────────────────────

  it('renders lat, lng inputs and radius label for GeoSearchField', () => {
    renderWithTooltips(
      <FilterControl field={geoField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toBeInTheDocument()
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toBeInTheDocument()
    expect(screen.getByText(/radius:/i)).toBeInTheDocument()
  })

  it('pre-populates default lat/lng from field metadata', () => {
    renderWithTooltips(
      <FilterControl field={geoField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(42.36)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(-71.06)
  })

  it('renders empty lat/lng when no defaults are set', () => {
    renderWithTooltips(
      <FilterControl field={geoFieldNoDefaults} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(null)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(null)
  })

  it('displays existing geo filter value', () => {
    renderWithTooltips(
      <FilterControl
        field={geoField}
        value={{ latitude: 40.7, longitude: -74.0, radiusMiles: 30 }}
        onChange={vi.fn()}
      />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(40.7)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(-74.0)
    expect(screen.getByText(/radius: 30 mi/i)).toBeInTheDocument()
  })

  it('calls onChange with undefined when clearing geo filter', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl
        field={geoField}
        value={{ latitude: 40.7, longitude: -74.0, radiusMiles: 30 }}
        onChange={onChange}
      />,
    )
    await user.click(screen.getByRole('button', { name: /clear location/i }))
    expect(onChange).toHaveBeenCalledWith(undefined)
  })

  // ── NumericalSearchField ──────────────────────────────────────────────────

  it('renders a number input with $ label for NumericalSearchField with DOLLARS unit', () => {
    renderWithTooltips(
      <FilterControl field={numericalField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /tuition/i })).toBeInTheDocument()
    expect(screen.getByText('$')).toBeInTheDocument()
  })

  it('renders existing value for NumericalSearchField', () => {
    renderWithTooltips(
      <FilterControl field={numericalField} value={{ value: 25000 }} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /tuition/i })).toHaveValue(25000)
  })

  it('calls onChange with { value } when typing in NumericalSearchField (after debounce)', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl field={numericalField} value={undefined} onChange={onChange} />,
    )
    await user.type(screen.getByRole('spinbutton', { name: /tuition/i }), '5000')
    await waitFor(() => expect(onChange).toHaveBeenLastCalledWith({ value: 5000 }), {
      timeout: 1000,
    })
  })

  it('clears NumericalSearchField when clear button is clicked', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl field={numericalField} value={{ value: 25000 }} onChange={onChange} />,
    )
    await user.click(screen.getByRole('button', { name: /clear tuition/i }))
    expect(onChange).toHaveBeenCalledWith(undefined)
  })

  // ── NumericalRangeSearchField ─────────────────────────────────────────────

  it('renders admission_rate as range with percentage label', () => {
    renderWithTooltips(
      <FilterControl field={admissionRateField} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /admission rate min/i })).toBeInTheDocument()
    expect(screen.getByRole('spinbutton', { name: /admission rate max/i })).toBeInTheDocument()
    expect(screen.getByText('%')).toBeInTheDocument()
  })

  it('displays percentage values as 0–100 for PERCENTAGE fields', () => {
    renderWithTooltips(
      <FilterControl
        field={admissionRateField}
        value={{ min: 0.2, max: 0.8 }}
        onChange={vi.fn()}
      />,
    )
    expect(screen.getByRole('spinbutton', { name: /admission rate min/i })).toHaveValue(20)
    expect(screen.getByRole('spinbutton', { name: /admission rate max/i })).toHaveValue(80)
  })

  it('converts percentage display values to 0–1 on change', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl field={admissionRateField} value={undefined} onChange={onChange} />,
    )
    await user.type(screen.getByRole('spinbutton', { name: /admission rate max/i }), '50')
    await waitFor(() => expect(onChange).toHaveBeenLastCalledWith({ max: 0.5 }), {
      timeout: 1000,
    })
  })

  it('renders enrollment range as dropdown selects', () => {
    renderWithTooltips(
      <FilterControl field={enrollmentField} value={undefined} onChange={vi.fn()} />,
    )
    // Enrollment fields use Select dropdowns instead of number inputs
    expect(screen.getByRole('textbox', { name: /enrollment min/i })).toBeInTheDocument()
    expect(screen.getByRole('textbox', { name: /enrollment max/i })).toBeInTheDocument()
    expect(screen.queryByText('%')).not.toBeInTheDocument()
    expect(screen.queryByText('$')).not.toBeInTheDocument()
  })

  it('clears NumericalRangeSearchField when clear button is clicked', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <FilterControl
        field={enrollmentField}
        value={{ min: 1000, max: 5000 }}
        onChange={onChange}
      />,
    )
    await user.click(screen.getByRole('button', { name: /clear enrollment/i }))
    expect(onChange).toHaveBeenCalledWith(undefined)
  })

  it('renders an info icon button for fields with descriptions', () => {
    renderWithTooltips(<FilterControl field={textField} value={undefined} onChange={vi.fn()} />)
    expect(
      screen.getByRole('button', { name: /info about institution name/i }),
    ).toBeInTheDocument()
  })

  it('shows description in tooltip on hover', async () => {
    const user = userEvent.setup()
    renderWithTooltips(<FilterControl field={textField} value={undefined} onChange={vi.fn()} />)
    await user.hover(screen.getByRole('button', { name: /info about institution name/i }))
    expect(await screen.findByRole('tooltip')).toHaveTextContent(
      'Full-text search on institution name',
    )
  })

  it('does not render info icon when description is empty', () => {
    const fieldNoDesc: SearchField = { ...textField, description: '' }
    renderWithTooltips(<FilterControl field={fieldNoDesc} value={undefined} onChange={vi.fn()} />)
    expect(screen.queryByRole('button', { name: /info about/i })).not.toBeInTheDocument()
  })
})

// ── MultiSelectCheckboxes ───────────────────────────────────────────────────

describe('MultiSelectCheckboxes', () => {
  const manyOptions = Array.from({ length: 8 }, (_, i) => ({
    value: `opt${i}`,
    displayName: `Option ${i}`,
  }))

  const scalableField: SearchField = {
    __typename: 'ChoiceSearchField',
    name: 'many',
    label: 'Many Options',
    description: '',
    theme: 'OTHER',
    visibility: 'VISIBLE',
    searchability: 'SEARCHABLE',
    exportable: false,
    options: manyOptions,
    maxSelections: null,
  }

  it('renders inline checkboxes without filter input below threshold', () => {
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={multiSelectField}
        options={multiSelectField.options!}
        maxSel={null}
        value={undefined}
        onChange={vi.fn()}
      />,
    )
    expect(screen.getByRole('checkbox', { name: /alpha/i })).toBeInTheDocument()
    expect(screen.queryByLabelText(/filter platforms options/i)).not.toBeInTheDocument()
  })

  it('renders a filter input when at or above threshold', () => {
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={scalableField}
        options={manyOptions}
        maxSel={null}
        value={undefined}
        onChange={vi.fn()}
      />,
    )
    expect(screen.getByLabelText(/filter many options options/i)).toBeInTheDocument()
  })

  it('filters options when typing in filter input', async () => {
    const user = userEvent.setup()
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={scalableField}
        options={manyOptions}
        maxSel={null}
        value={undefined}
        onChange={vi.fn()}
      />,
    )
    await user.type(screen.getByLabelText(/filter many options options/i), 'Option 3')
    expect(screen.getByText('Option 3')).toBeInTheDocument()
    expect(screen.queryByText('Option 0')).not.toBeInTheDocument()
  })

  it('shows "No matching options" when filter matches nothing', async () => {
    const user = userEvent.setup()
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={scalableField}
        options={manyOptions}
        maxSel={null}
        value={undefined}
        onChange={vi.fn()}
      />,
    )
    await user.type(screen.getByLabelText(/filter many options options/i), 'zzz')
    expect(screen.getByText(/no matching options/i)).toBeInTheDocument()
  })

  it('calls onChange with { values } when checking a checkbox', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={multiSelectField}
        options={multiSelectField.options!}
        maxSel={null}
        value={undefined}
        onChange={onChange}
      />,
    )
    await user.click(screen.getByRole('checkbox', { name: /alpha/i }))
    expect(onChange).toHaveBeenCalledWith({ values: ['a'] })
  })

  it('calls onChange with undefined when unchecking the last checkbox', async () => {
    const user = userEvent.setup()
    const onChange = vi.fn()
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={multiSelectField}
        options={multiSelectField.options!}
        maxSel={null}
        value={{ values: ['a'] }}
        onChange={onChange}
      />,
    )
    await user.click(screen.getByRole('checkbox', { name: /alpha/i }))
    expect(onChange).toHaveBeenCalledWith(undefined)
  })

  it('disables unchecked checkboxes when maxSel limit is reached', () => {
    renderWithTooltips(
      <MultiSelectCheckboxes
        field={multiSelectField}
        options={multiSelectField.options!}
        maxSel={1}
        value={{ values: ['a'] }}
        onChange={vi.fn()}
      />,
    )
    expect(screen.getByRole('checkbox', { name: /alpha/i })).toBeEnabled()
    expect(screen.getByRole('checkbox', { name: /beta/i })).toBeDisabled()
  })
})

describe('GeoFilterControl preferences integration', () => {
  it('uses preferences store defaults when field has no defaults', () => {
    mockPreferencesStore.homeLatitude = 33.749
    mockPreferencesStore.homeLongitude = -84.388

    renderWithTooltips(
      <FilterControl field={geoFieldNoDefaults} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(33.749)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(-84.388)
  })

  it('prefers field defaults over preferences store', () => {
    mockPreferencesStore.homeLatitude = 33.749
    mockPreferencesStore.homeLongitude = -84.388

    renderWithTooltips(
      <FilterControl field={geoField} value={undefined} onChange={vi.fn()} />,
    )
    // geoField has defaultLatitude=42.36, defaultLongitude=-71.06
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(42.36)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(-71.06)
  })

  it('renders empty when no field defaults and no preferences', () => {
    renderWithTooltips(
      <FilterControl field={geoFieldNoDefaults} value={undefined} onChange={vi.fn()} />,
    )
    expect(screen.getByRole('spinbutton', { name: /location latitude/i })).toHaveValue(null)
    expect(screen.getByRole('spinbutton', { name: /location longitude/i })).toHaveValue(null)
  })
})

import { describe, it, expect, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MantineProvider } from '@mantine/core'
import { ColumnPicker } from './ColumnPicker'
import type { SearchOutputField } from './types'

const baseField: Omit<SearchOutputField, 'name' | 'label' | 'theme'> = {
  description: '',
  visibility: 'VISIBLE',
  exportable: true,
  defaultVisible: true,
  sortable: false,
  unit: null,
  outputKey: null,
}

const OUTPUT_FIELDS: SearchOutputField[] = [
  { ...baseField, name: 'name', label: 'Name', theme: 'CORE' },
  { ...baseField, name: 'city', label: 'City', theme: 'CORE' },
  { ...baseField, name: 'enrollment', label: 'Enrollment', theme: 'ACADEMICS' },
  { ...baseField, name: 'tuition', label: 'Tuition', theme: 'COST' },
  { ...baseField, name: 'hidden', label: 'Hidden', theme: 'CORE', visibility: 'HIDDEN' },
]

function renderPicker(props?: Partial<React.ComponentProps<typeof ColumnPicker>>) {
  const defaultProps = {
    outputFields: OUTPUT_FIELDS,
    visibleColumns: new Set(['name', 'city', 'enrollment']),
    onToggleColumn: vi.fn(),
    columnOrder: ['city', 'enrollment'],
    onReorderColumn: vi.fn(),
    onSetColumnOrder: vi.fn(),
  }
  return render(
    <MantineProvider>
      <ColumnPicker {...defaultProps} {...props} />
    </MantineProvider>,
  )
}

describe('ColumnPicker', () => {
  it('renders a Columns button', () => {
    renderPicker()
    expect(screen.getByRole('button', { name: /columns/i })).toBeInTheDocument()
  })

  it('shows column checkboxes when clicked', async () => {
    const user = userEvent.setup()
    renderPicker()
    await user.click(screen.getByRole('button', { name: /columns/i }))
    expect(screen.getByRole('checkbox', { name: /name/i })).toBeInTheDocument()
