    expect(screen.queryByTestId('theme-group-ACADEMICS')).not.toBeInTheDocument()
    expect(screen.queryByTestId('theme-group-COST')).not.toBeInTheDocument()
  })

  it('groups consecutive extra columns by theme for header row', () => {
    const fields: SearchOutputField[] = [
      { ...baseOutputField, name: 'name', label: 'Name', theme: 'CORE' },
      { ...baseOutputField, name: 'city', label: 'City', theme: 'CORE' },
