      { ...baseOutputField, name: 'tuition_in_state', label: 'Tuition (In-State)', theme: 'COST', unit: 'DOLLARS', outputKey: 'cost.tuitionInState' },
      { ...baseOutputField, name: 'enrollment', label: 'Enrollment', theme: 'ACADEMICS', outputKey: 'academics.enrollment' },
    ]
    // columnOrder puts enrollment before tuition — so ACADEMICS before COST
    renderTable({
      outputFields: fields,
      visibleColumns: new Set(['name', 'city', 'state', 'enrollment', 'tuition_in_state']),
      columnOrder: ['city', 'state', 'enrollment', 'tuition_in_state'],
    })
    const headers = screen.getAllByRole('columnheader')
    const academicsIdx = headers.findIndex((h) => h.textContent === 'Academics')
    const costIdx = headers.findIndex((h) => h.textContent === 'Cost & Financial Aid')
    expect(academicsIdx).toBeLessThan(costIdx)
  })
})

