    renderSearch()
    expect(screen.getByText(/100\+ results/i)).toBeInTheDocument()
  })

  // ── Location, distance, and myPrice ────────────────────────────────────────

  it('renders LocationInput in the sidebar', () => {
    renderSearch()
    expect(screen.getByText(/your location/i)).toBeInTheDocument()
    expect(screen.getByPlaceholderText('e.g. 02134')).toBeInTheDocument()
  })

  it('shows distance column when userLocation is in URL params', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 42.3, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0')
    expect(screen.getByTestId('distance')).toHaveTextContent('42 mi')
  })

  it('shows "< 1 mi" for very short distances', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 0.3, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0')
    expect(screen.getByTestId('distance')).toHaveTextContent('< 1 mi')
  })

  it('shows myPrice column when userLocation has state', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: 10, myPrice: 15000 },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch('/search?userLat=42.0&userLng=-72.0&userState=MA')
    expect(screen.getByTestId('my-price')).toHaveTextContent('$15,000')
  })

  it('does not show distance column when no userLocation', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: [
            { unitID: '1', name: 'MIT', city: 'Cambridge', state: 'MA', distance: null, myPrice: null },
          ],
          total: 1,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    expect(screen.queryByTestId('distance')).not.toBeInTheDocument()
  })

  it('shows sort control dropdown', () => {
    renderSearch()
    expect(screen.getByRole('textbox', { name: /sort field/i })).toBeInTheDocument()
  })

  it('passes userLocation and sort to search query variables', () => {
    renderSearch('/search?userLat=42.0&userLng=-72.0&userState=MA&sort=distance')
    const searchCall = mockUseQuery.mock.calls.find(
      (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
        getOperationName(call[0].query) === 'Search',
    )
    expect(searchCall).toBeDefined()
    expect(searchCall![0].variables).toEqual(
      expect.objectContaining({
        userLocation: { latitude: 42, longitude: -72, state: 'MA' },
        sort: { field: 'distance', direction: 'ASC' },
      }),
    )
  })

  it('caps pagination total pages to respect 100 result maximum', () => {
    setupMocks(undefined, {
      data: {
        search: {
          results: Array.from({ length: 20 }, (_, i) => ({
            unitID: String(i),
            name: `School ${i}`,
            city: 'City',
            state: 'ST',
          })),
          total: 500,
          limit: 20,
          offset: 0,
        },
      },
    })
    renderSearch()
    // With pageSize 20 and max 100, there should be 5 pages max
    // Mantine Pagination renders page buttons — check that page 6 doesn't exist
    const paginationControls = screen.getByTestId('pagination-controls')
    expect(paginationControls).toBeInTheDocument()
    // Page 5 should exist but page 6 should not
    expect(screen.queryByRole('button', { name: '6' })).not.toBeInTheDocument()
  })

  // ── Text input debounce ──────────────────────────────────────────────────

  it('updates search query after debounce when typing in a text field', async () => {
    const user = userEvent.setup()
    renderSearch()
    const input = screen.getByRole('textbox', { name: /institution name/i })
    await user.type(input, 'MIT')
    // Input shows the typed value immediately
    expect(input).toHaveValue('MIT')
    // After debounce, the search query should include the filter
    await waitFor(
      () => {
        const searchCalls = mockUseQuery.mock.calls.filter(
          (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
            getOperationName(call[0].query) === 'Search',
        )
        const lastSearchCall = searchCalls[searchCalls.length - 1]
        expect(lastSearchCall[0].variables.filters).toEqual(
          expect.arrayContaining([
            expect.objectContaining({ field: 'name', value: { query: 'MIT' } }),
          ]),
        )
      },
      { timeout: 1000 },
    )
  })

  it('debounces clearing a text field', async () => {
    const user = userEvent.setup()
    renderSearch('/search?name=MIT')
    const input = screen.getByRole('textbox', { name: /institution name/i })
    expect(input).toHaveValue('MIT')
    await user.clear(input)
    expect(input).toHaveValue('')
    // After debounce, the filter should be removed
    await waitFor(
      () => {
        const searchCalls = mockUseQuery.mock.calls.filter(
          (call: Array<{ query: unknown; variables?: Record<string, unknown> }>) =>
            getOperationName(call[0].query) === 'Search',
        )
        const lastCall = searchCalls[searchCalls.length - 1]
        const nameFilter = lastCall[0].variables.filters.find(
          (f: { field: string }) => f.field === 'name',
        )
        expect(nameFilter).toBeUndefined()
      },
      { timeout: 1000 },
