    expect(toggle).toBeInTheDocument()
  })

  it('defaults to card view and renders institution cards', () => {
    renderSearch()
    // Card view renders institution names inside cards (role="button" from InstitutionCard)
    const buttons = screen.getAllByRole('button')
    const mitButton = buttons.find((b) => b.textContent?.includes('MIT'))
    expect(mitButton).toBeDefined()
  })

  it('switches to table view when table segment is selected', async () => {
    const user = userEvent.setup()
    renderSearch()
    const radios = screen.getAllByRole('radio')
    const tableRadio = radios.find((r) => r.getAttribute('value') === 'table')!
    await user.click(tableRadio)
    // Table view renders a <table> element
    expect(screen.getByRole('table')).toBeInTheDocument()
  })

  it('hides ColumnPicker when not in table view', () => {
    renderSearch()
    // Default is card view — ColumnPicker button should not be present
    expect(screen.queryByRole('button', { name: /columns/i })).not.toBeInTheDocument()
  })

  it('shows ColumnPicker when in table view', async () => {
    const user = userEvent.setup()
    renderSearch()
    const radios = screen.getAllByRole('radio')
    const tableRadio = radios.find((r) => r.getAttribute('value') === 'table')!
    await user.click(tableRadio)
    expect(screen.getByRole('button', { name: /columns/i })).toBeInTheDocument()
  })

  it('restores view mode from URL param', () => {
    renderSearch('/search?view=table')
    expect(screen.getByRole('table')).toBeInTheDocument()
  })

  it('persists view mode to localStorage on change', async () => {
    const user = userEvent.setup()
    renderSearch()
    const radios = screen.getAllByRole('radio')
    const listRadio = radios.find((r) => r.getAttribute('value') === 'list')!
    await user.click(listRadio)
    expect(localStorage.getItem('kapow:results-view')).toBe('list')
  })

  // ── Export CSV ──────────────────────────────────────────────────────────────

  it('renders Export CSV button when results are present', () => {
    renderSearch()
    const button = screen.getByRole('button', { name: /export csv/i })
    expect(button).toBeInTheDocument()
    expect(button).not.toBeDisabled()
  })

  it('Export CSV button is disabled when no results', () => {
    setupMocks(undefined, {
      data: { search: { results: [], total: 0, limit: 20, offset: 0 } },
    })
    renderSearch()
    const button = screen.getByRole('button', { name: /export csv/i })
    expect(button).toBeDisabled()
  })

  it('changes page size and resets page to 1 when page size is changed', async () => {
    const user = userEvent.setup()
    setupMocks(undefined, {
      data: {
        search: {
          results: Array.from({ length: 10 }, (_, i) => ({
            unitID: String(i),
            name: `School ${i}`,
            city: 'City',
            state: 'ST',
          })),
          total: 80,
          limit: 10,
          offset: 10,
        },
      },
    })
    renderSearch('/search?page=2&pageSize=10')
    const pageSizeSelect = screen.getByLabelText(/per page/i)
    await user.selectOptions(pageSizeSelect, '50')
    // After changing page size, page param should be reset
    // The mock implementation will reflect the new variables on next render
    const lastCall = mockUseQuery.mock.calls
      .filter(
        (call: Array<{ query: unknown }>) => getOperationName(call[0].query) === 'Search',
      )
      .pop()
    expect(lastCall![0].variables).toEqual(
      expect.objectContaining({ limit: 50, offset: 0 }),
    )
  })
})

