    renderPicker()
    await user.click(screen.getByRole('button', { name: /columns/i }))

    const cityItem = screen.getByTestId('column-order-item-city')
    expect(cityItem).toHaveAttribute('draggable', 'true')

    const enrollmentItem = screen.getByTestId('column-order-item-enrollment')
    expect(enrollmentItem).toHaveAttribute('draggable', 'true')
