import { describe, it, expect, vi } from 'vitest'
import { render, screen } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { MantineProvider } from '@mantine/core'
import { ResultsTable } from './ResultsTable'
import type { SearchInstitution, SearchOutputField } from './types'

const baseOutputField: Omit<SearchOutputField, 'name' | 'label' | 'theme'> = {
  description: '',
  visibility: 'VISIBLE',
  exportable: true,
  defaultVisible: true,
  sortable: false,
  unit: null,
  outputKey: null,
}

const OUTPUT_FIELDS: SearchOutputField[] = [
  { ...baseOutputField, name: 'name', label: 'Name', theme: 'CORE' },
  { ...baseOutputField, name: 'city', label: 'City', theme: 'CORE' },
  { ...baseOutputField, name: 'state', label: 'State', theme: 'CORE' },
  {
    ...baseOutputField,
    name: 'enrollment',
    label: 'Enrollment',
    theme: 'ACADEMICS',
    outputKey: 'academics.enrollment',
  },
  {
    ...baseOutputField,
    name: 'tuition_in_state',
    label: 'Tuition (In-State)',
    theme: 'COST',
    unit: 'DOLLARS',
    outputKey: 'cost.tuitionInState',
  },
]

const INSTITUTIONS: SearchInstitution[] = [
  {
    unitID: '166683',
    name: 'MIT',
    city: 'Cambridge',
    state: 'MA',
    distance: 42.3,
    myPrice: 15000,
    academics: { enrollment: 11000 },
    cost: { tuitionInState: 55000 },
  },
  {
    unitID: '130794',
    name: 'Harvard University',
    city: 'Cambridge',
    state: 'MA',
    distance: 40,
    myPrice: 18000,
    academics: { enrollment: 21000 },
    cost: { tuitionInState: 57000 },
  },
]

function renderTable(props?: Partial<React.ComponentProps<typeof ResultsTable>>) {
  const visibleColumns = props?.visibleColumns ?? new Set(['name', 'city', 'state'])
  const columnOrder = props?.columnOrder ?? Array.from(visibleColumns).filter((n) => n !== 'name')
  const defaultProps = {
    institutions: INSTITUTIONS,
    outputFields: OUTPUT_FIELDS,
    visibleColumns,
    columnOrder,
    onClickInstitution: vi.fn(),
    hasLocation: false,
    hasState: false,
  }
  return render(
    <MantineProvider>
      <ResultsTable {...defaultProps} {...props} />
    </MantineProvider>,
  )
}

describe('ResultsTable', () => {
  it('renders institution names in table rows', () => {
    renderTable()
    expect(screen.getByText('MIT')).toBeInTheDocument()
    expect(screen.getByText('Harvard University')).toBeInTheDocument()
  })

  it('renders city and state columns', () => {
    renderTable()
    expect(screen.getAllByText('Cambridge').length).toBe(2)
    expect(screen.getAllByText('MA').length).toBe(2)
  })

  it('renders column headers', () => {
    renderTable()
    expect(screen.getByText('Name')).toBeInTheDocument()
    expect(screen.getByText('City')).toBeInTheDocument()
    expect(screen.getByText('State')).toBeInTheDocument()
  })

  it('shows distance column when hasLocation is true', () => {
    renderTable({
      hasLocation: true,
      columnOrder: ['city', 'state', 'distance'],
    })
    expect(screen.getByText('Distance')).toBeInTheDocument()
    expect(screen.getByText('42 mi')).toBeInTheDocument()
  })

  it('does not show distance column when hasLocation is false', () => {
    renderTable({
      hasLocation: false,
      columnOrder: ['city', 'state', 'distance'],
    })
    expect(screen.queryByText('Distance')).not.toBeInTheDocument()
  })

  it('shows myPrice column when hasState is true', () => {
    renderTable({
      hasState: true,
      columnOrder: ['city', 'state', 'myPrice'],
    })
    expect(screen.getByText('My Price')).toBeInTheDocument()
    expect(screen.getByText('$15,000')).toBeInTheDocument()
  })

  it('does not show myPrice column when hasState is false', () => {
    renderTable({
      hasState: false,
      columnOrder: ['city', 'state', 'myPrice'],
    })
    expect(screen.queryByText('My Price')).not.toBeInTheDocument()
  })

  it('renders extra visible columns with formatted values', () => {
    renderTable({
      visibleColumns: new Set(['name', 'city', 'state', 'enrollment', 'tuition_in_state']),
    })
    expect(screen.getByText('Enrollment')).toBeInTheDocument()
    expect(screen.getByText('Tuition (In-State)')).toBeInTheDocument()
    expect(screen.getByText('11000')).toBeInTheDocument()
    expect(screen.getByText('$55,000')).toBeInTheDocument()
  })

  it('does not render extra columns that are not in visibleColumns', () => {
    renderTable({ visibleColumns: new Set(['name', 'city', 'state']) })
    expect(screen.queryByText('Enrollment')).not.toBeInTheDocument()
  })

  it('calls onClickInstitution when a row is clicked', async () => {
    const user = userEvent.setup()
    const onClickInstitution = vi.fn()
    renderTable({ onClickInstitution })
    await user.click(screen.getByText('MIT'))
    expect(onClickInstitution).toHaveBeenCalledWith('166683')
  })

  it('formats "< 1 mi" for short distances', () => {
    renderTable({
      hasLocation: true,
      columnOrder: ['city', 'state', 'distance'],
      institutions: [{ unitID: '1', name: 'Nearby U', city: 'Town', state: 'ST', distance: 0.3 }],
    })
    expect(screen.getByText('< 1 mi')).toBeInTheDocument()
  })

  it('shows dash for null distance', () => {
    renderTable({
      hasLocation: true,
      columnOrder: ['city', 'state', 'distance'],
      institutions: [
        { unitID: '1', name: 'Far U', city: 'Town', state: 'ST', distance: null },
      ],
    })
    expect(screen.getByTestId('distance')).toHaveTextContent('—')
  })

  it('shows dash for null myPrice', () => {
    renderTable({
      hasState: true,
      columnOrder: ['city', 'state', 'myPrice'],
      institutions: [
        { unitID: '1', name: 'Cheap U', city: 'Town', state: 'ST', myPrice: null },
      ],
    })
