// useQuery is called twice per render: once for SearchFieldsQuery, once for SearchQuery.
// We dispatch on the operation name. In Vitest with vi.mock('urql'), args.query is the
// raw template string; in production it is a TypedDocumentNode. getOperationName handles both.
const { mockUseQuery } = vi.hoisted(() => ({ mockUseQuery: vi.fn() }))
vi.mock('urql', () => ({ useQuery: mockUseQuery }))
vi.mock('@/stores/preferencesStore', () => ({
  usePreferencesStore: (selector: (s: Record<string, unknown>) => unknown) =>
    selector({ homeLatitude: null, homeLongitude: null, homeState: null, loaded: false, loading: false, load: vi.fn(), update: vi.fn(), clear: vi.fn() }),
}))
vi.mock('@mantine/hooks', async () => {
  const actual = await vi.importActual('@mantine/hooks')
  return { ...actual, useMediaQuery: () => true }
})

function getOperationName(query: unknown): string {
  // In Vitest with vi.mock('urql'), args.query arrives as the raw template string.
  // In production (and some test environments), it is a DocumentNode.
  if (typeof query === 'string') {
    const match = query.match(/^\s*(?:query|mutation|subscription)\s+(\w+)/m)
    return match?.[1] ?? ''
  }
  if (typeof query !== 'object' || query === null) return ''
  const doc = query as { definitions?: Array<{ name?: { value?: string } }> }
  return doc.definitions?.[0]?.name?.value ?? ''
}

